const FOTOS = [
  { dorsal: 11, ape: "LOPEZ", src: "data:image/png;base64," },
];
function fotoDe(p) {
  if (p.foto) return p.foto;
  const ap = (p.apellidos || "").toUpperCase();
  const f = FOTOS.find((x) => String(x.dorsal) === String(p.dorsal) && ap.includes(x.ape));
  return f ? f.src : "";
}


