function fechasDe(campeonato) {
  const series = CAMP_SERIES[campeonato] || [];
  const arr = [];
  series.forEach((s) => SERIES[s].forEach((f) => arr.push({ ...f, serie: s })));
  return arr.sort((a, b) => a.ini.localeCompare(b.ini));
}
