/* Escalas de puntos federadas */
const ESCALAS = {
  CAMOD: { carrera: [15, 12, 10, 8, 6, 5, 4, 3, 2, 1], pole: [7, 6, 5, 4, 3, 2, 2, 1, 1] },
  FMC: { carrera: [15, 12, 10, 8, 6, 5, 4, 3, 2, 1], pole: [7.5, 6, 5, 4, 3, 2.5, 2, 1.5, 1, 0.5] },
};
const escalaDe = (camp) => (camp && camp.startsWith("CAV") ? "CAMOD" : "FMC");
const federacionDe = (camp) => (camp && camp.startsWith("CAV") ? "CAMOD" : "FMC / FedeMoto Chile");
function calcularPuntos(camp, tanda, pos) {
  const e = ESCALAS[escalaDe(camp)];
  const tabla = tanda === "Pole" ? e.pole : e.carrera;
  return tabla[pos - 1] ?? 0;
}
const fmtPts = (n) => (Number.isInteger(n) ? String(n) : String(n).replace(".", ","));
const nombreCompleto = (p) => `${p.nombres || ""} ${p.apellidos || ""}`.trim();
function edadDe(iso) {
  if (!iso) return null;
  const b = new Date(iso); if (isNaN(b.getTime())) return null;
  const t = new Date(); let a = t.getFullYear() - b.getFullYear();
  const m = t.getMonth() - b.getMonth();
  if (m < 0 || (m === 0 && t.getDate() < b.getDate())) a--;
  return a >= 0 && a < 120 ? a : null;
}

/* ---------- Cobros por fecha ---------- */
/* Precio por familia de categoría y moneda (CAV cargado; CLP/anual por definir) */
const VALOR_FECHA = {
  "Gp3 cup": { ARS: 330000, USD: 240, CLP: null },
  "SBK": { ARS: 540000, USD: 390, CLP: null },
};
function familiaCategoria(cat) {
  if (!cat) return null;
  if (cat === "Gp1 Talent") return "BLOQUEADA";        // no disponible para cobro
  if (cat.startsWith("Gp3 Cup")) return "Gp3 cup";
  if (cat.startsWith("SBK") || cat === "Sportbike 7") return "SBK"; // Sportbike 7 cobra como SBK
  return null;
}
const catBloqueada = (cat) => familiaCategoria(cat) === "BLOQUEADA";
function valorSugerido(cat, moneda) {
  const fam = familiaCategoria(cat);
  if (!fam || fam === "BLOQUEADA" || !VALOR_FECHA[fam]) return null;
  const v = VALOR_FECHA[fam][moneda];
  return v == null ? null : v;
}
/* Modo de cobro: por fecha (CAV/Binacional) vs abono anual (CCV/Moto4/Junior) */
function modoDe(campeonato) {
  if (!campeonato) return "fecha";
  if (campeonato.startsWith("CAV") || campeonato.includes("Binacional")) return "fecha";
  return "abono";
}
function monedasDe(campeonato) {
  if (!campeonato) return ["CLP"];
  if (campeonato.includes("Binacional")) return ["ARS", "CLP", "USD"]; // único multimoneda
  if (campeonato.startsWith("CAV")) return ["ARS"];
  if (campeonato.startsWith("Moto 4")) return ["USD"];                  // Moto 4 solo USD
  return ["CLP"];                                                       // CCV, Gp3 Junior
}
function mediosDe(campeonato) {
  const base = ["Efectivo", "Transferencia"];
  if ((campeonato || "").includes("CCV")) base.push("Tarjeta"); // tarjeta solo CCV y binacional
  return base;
}
const fmtMoneda = (n, m) => `${m} $${new Intl.NumberFormat("es-CL").format(Math.round(Number(n) || 0))}`;

