/* ---------- Persistencia (Supabase) ---------- */
const DB_KEY = "gp3-acred-db-v5";
const ADMIN_PIN = "2026";
let MEM = null;

async function loadDB() {
  try {
    const { data, error } = await supabase
      .from("app_state")
      .select("value")
      .eq("key", DB_KEY)
      .maybeSingle();
    if (error) throw error;
    if (data && data.value) { MEM = data.value; return data.value; }
  } catch (e) { console.error("loadDB", e); }
  return MEM;
}

async function saveDB(db) {
  MEM = db;
  try {
    const { error } = await supabase
      .from("app_state")
      .upsert({ key: DB_KEY, value: db, updated_at: new Date().toISOString() });
    if (error) throw error;
  } catch (e) { console.error("saveDB", e); }
}

/* ---------- Helpers ---------- */
function ultimoResultado(db, pilotoId) {
  const rs = db.resultados
    .filter((r) => r.pilotoId === pilotoId && r.tanda === "Carrera")
    .sort((a, b) => (TODAS_FECHAS[b.fechaId]?.ini || "").localeCompare(TODAS_FECHAS[a.fechaId]?.ini || ""));
  return rs[0] || null;
}
function folioNuevo(db) {
  const n = db.acreditaciones.length + 1;
  return `GP3-2026-${String(n).padStart(4, "0")}`;
}
const esArg = (p) => p.pais === "Argentina";

/* ============================================================ */
export default function App() {
  const [db, setDb] = useState(null);
  const [rol, setRol] = useState(null);

  useEffect(() => {
    (async () => {
      let d = await loadDB();
      if (!d || d.v !== 5) { d = seed(); await saveDB(d); }
      setDb(d);
    })();
  }, []);
  const persist = (next) => { setDb(next); saveDB(next); };

  if (!db) return <Splash />;
  return (
    <div className="gp3-root">
      <StyleSheet />
      <TopBar rol={rol} onHome={() => setRol(null)} />
      <main className="gp3-main">
        {!rol && <Landing onPick={setRol} />}
        {rol === "acreditacion" && <AcreditacionFlow db={db} persist={persist} />}
        {rol === "org" && <OrgFlow db={db} persist={persist} />}
      </main>
    </div>
  );
}

function Splash() {
  return (<div className="gp3-root"><StyleSheet /><div className="splash"><Flag size={28} /><span>Cargando GP3 Sports…</span></div></div>);
}

function TopBar({ rol, onHome }) {
  const etiqueta = { piloto: "Portal del Piloto", acreditacion: "Acreditación en Pista", org: "Organización" }[rol];
  return (
    <header className="topbar">
      <button className="brand" onClick={onHome} title="Inicio">
        <img className="brand-img" src={LOGO_GP3} alt="GP3 Sports LATAM" />
        <span className="brand-sub">ACREDITACIÓN</span>
      </button>
      {rol && (<div className="topbar-right"><span className="role-chip">{etiqueta}</span><button className="btn-ghost" onClick={onHome}><LogOut size={15} /> Salir</button></div>)}
    </header>
  );
}

/* Logo de campeonato (placeholder reemplazable por imagen real) */
function CampLogo({ campeonato, size = 40 }) {
  const img = CAMP_IMG[campeonato];
  if (img) {
    return (
      <span className="camp-logo img" title={campeonato}>
        <img src={img} alt={metaDe(campeonato).abbr} style={{ height: size }} />
      </span>
    );
  }
  const m = metaDe(campeonato);
  return (
    <span className="camp-logo" style={{ width: size, height: size, background: m.color }} title={campeonato}>
      {m.abbr}
    </span>
  );
}

/* ---------------- Landing ---------------- */
function Landing({ onPick }) {
  const lanes = [
    { id: "acreditacion", icon: <ShieldCheck size={22} />, kicker: "Acreditación", title: "Acreditar pilotos", desc: "Flujo único: elige el piloto de la lista, edita su ficha, cobra o registra el abono y emite el pase para imprimir." },
    { id: "org", icon: <Users size={22} />, kicker: "Organización · Mantenedor", title: "Pilotos, calendario y ranking", desc: "Crea y edita los pilotos, gestiona el calendario y administra los puntajes y el ranking." },
  ];
  return (
    <div className="landing">
      <div className="landing-hero">
        <span className="eyebrow">Temporada 2026 · CCV · CAV · Binacional</span>
        <h1>Del box a la pista,<br /><span className="accent">sin fricción.</span></h1>
        <p>Un solo camino: incorporar al piloto, que valide su ficha y acreditarlo el día de carrera con un pase impreso y firmado.</p>
      </div>
      <div className="grid-lanes">
        {lanes.map((l, i) => (
          <button key={l.id} className="lane" onClick={() => onPick(l.id)}>
            <span className="lane-pos">{String(i + 1).padStart(2, "0")}</span>
            <span className="lane-icon">{l.icon}</span>
            <span className="lane-kicker">{l.kicker}</span>
            <span className="lane-title">{l.title}</span>
            <span className="lane-desc">{l.desc}</span>
            <span className="lane-go">Entrar <ChevronRight size={16} /></span>
          </button>
        ))}
      </div>
    </div>
  );
}

/* ============================================================
   PILOTO
   ============================================================ */
function PilotoFlow({ db, persist }) {
  const [pid, setPid] = useState(null);
  const [doc, setDoc] = useState("");
  const [err, setErr] = useState("");
  const [tab, setTab] = useState("ficha");
  const piloto = db.pilotos.find((p) => p.id === pid);

  const ingresar = () => {
    const limpio = doc.trim().toLowerCase().replace(/[.\s]/g, "");
    const p = db.pilotos.find((x) => (x.dni || "").toLowerCase().replace(/[.\s]/g, "") === limpio);
    if (!p) { setErr("No encontramos ese documento. Verifícalo o pide a la organización que cargue tu ficha base."); return; }
    setErr(""); setPid(p.id);
  };

  if (!piloto) {
    return (
      <div className="login-wrap">
        <div className="login-card">
          <span className="eyebrow">Portal del Piloto</span>
          <h2>Ingresa con tu documento</h2>
          <p className="muted">DNI / RUT / CPF — el mismo que la organización registró en tu ficha.</p>
          <input className="inp" placeholder="Ej: 20.114.882-3" value={doc}
            onChange={(e) => setDoc(e.target.value)} onKeyDown={(e) => e.key === "Enter" && ingresar()} />
          {err && <div className="alert">{err}</div>}
          <button className="btn-primary full" onClick={ingresar}>Ingresar <ChevronRight size={16} /></button>
          <div className="hint">Demo: <code>20.114.882-3</code> (Valentina, CCV) · <code>38.221.554</code> (Lucas, CAV — reportó error).</div>
        </div>
      </div>
    );
  }

  const tabs = [
    { id: "ficha", label: "Mi ficha", icon: <User size={15} /> },
    { id: "preacred", label: "Pre-acreditación", icon: <ClipboardCheck size={15} /> },
    { id: "historia", label: "Mi historia", icon: <Clock size={15} /> },
    { id: "ranking", label: "Mi ranking", icon: <Trophy size={15} /> },
  ];
  return (
    <div className="portal">
      <PilotoHeader piloto={piloto} />
      <nav className="subnav">
        {tabs.map((t) => (
          <button key={t.id} className={`subnav-btn ${tab === t.id ? "on" : ""}`} onClick={() => setTab(t.id)}>{t.icon}<span>{t.label}</span></button>
        ))}
      </nav>
      {tab === "ficha" && <PilotoFicha db={db} persist={persist} piloto={piloto} />}
      {tab === "preacred" && <PilotoPreacred db={db} persist={persist} piloto={piloto} />}
      {tab === "historia" && <PilotoHistoria db={db} piloto={piloto} />}
      {tab === "ranking" && <PilotoRanking db={db} piloto={piloto} />}
    </div>
  );
}

function PilotoHeader({ piloto }) {
  const estado = piloto.estadoFicha;
  const foto = fotoDe(piloto);
  return (
    <div className="piloto-head">
      <div className="ph-media">
        <div className="ph-photo">{foto ? <img src={foto} alt={nombreCompleto(piloto)} /> : <User size={40} />}</div>
        <div className="ph-dorsal">{piloto.dorsal}</div>
        <CampLogo campeonato={piloto.campeonato} size={26} />
      </div>
      <div className="piloto-id">
        <h2>{nombreCompleto(piloto)}</h2>
        <div className="piloto-meta">
          <span><Bike size={13} /> {piloto.categoria}</span>
          <span><Flag size={13} /> {piloto.campeonato.split(" - ")[0]}</span>
          <span><Users size={13} /> {piloto.equipo}</span>
        </div>
        {estado === "confirmada" && <span className="state-chip ok"><BadgeCheck size={14} /> Ficha confirmada</span>}
        {estado === "pendiente" && <span className="state-chip warn"><Clock size={14} /> Sin confirmar</span>}
        {estado === "rechazada" && <span className="state-chip red"><AlertTriangle size={14} /> Error reportado</span>}
      </div>
    </div>
  );
}

/* Ficha CAMOD — solo lectura para el piloto + confirmar / rechazar */
function PilotoFicha({ db, persist, piloto }) {
  const setEstado = (estadoFicha) =>
    persist({ ...db, pilotos: db.pilotos.map((p) => (p.id === piloto.id ? { ...p, estadoFicha } : p)) });

  return (
    <div className="panel">
      <div className="panel-head"><h3>Gestiona tu acreditación</h3><span className="muted small">Datos requeridos por CAMOD</span></div>
      <p className="muted small">Esta es tu información base, cargada por la organización. No es editable aquí: revísala con atención, porque es la que irá en tu pase.</p>

      <FichaFields data={piloto} edit={false} />

      {piloto.estadoFicha === "rechazada" ? (
        <div className="reject-msg">
          <AlertTriangle size={20} />
          <div>
            <b>Reportaste una discrepancia en tus datos.</b>
            <p>Acércate al <b>staff de GP3 en pista</b> para corregir tu información y finalizar tu acreditación por el conducto normal. El staff actualizará tu ficha presencialmente.</p>
          </div>
          <button className="btn-ghost" onClick={() => setEstado("pendiente")}>Cancelar reporte</button>
        </div>
      ) : (
        <div className="panel-actions">
          {piloto.estadoFicha === "confirmada"
            ? <span className="ok-text small"><BadgeCheck size={14} /> Confirmaste que tus datos son correctos.</span>
            : <button className="btn-primary" onClick={() => setEstado("confirmada")}><Check size={16} /> Mis datos están correctos</button>}
          <button className="btn-outline" onClick={() => setEstado("rechazada")}><X size={15} /> Hay un error en mis datos</button>
        </div>
      )}
    </div>
  );
}

function PilotoPreacred({ db, persist, piloto }) {
  const todas = fechasDe(piloto.campeonato).filter((f) => !f.historica);
  const ultimo = ultimoResultado(db, piloto.id);
  const ultFecha = ultimo ? TODAS_FECHAS[ultimo.fechaId] : null;
  const [sel, setSel] = useState(null);     // fecha a confirmar
  const [aviso, setAviso] = useState(null); // popup "no disponible"
  const fecha = todas.find((f) => f.id === sel);
  const enCurso = (fid) => db.fechasEstado?.[fid] === "en_curso";
  const yaPre = (fid) => db.acreditaciones.find((a) => a.pilotoId === piloto.id && a.fechaId === fid);
  const bloqueado = piloto.estadoFicha === "rechazada";

  const confirmar = () => {
    if (!fecha || bloqueado) return;
    const reg = {
      id: `acr-${piloto.id}-${fecha.id}`, pilotoId: piloto.id, fechaId: fecha.id,
      estado: "pre-acreditado", creado: new Date().toISOString(),
      snapshot: snapshotDe(piloto),
    };
    const otras = db.acreditaciones.filter((a) => a.id !== reg.id);
    persist({ ...db, acreditaciones: [...otras, reg] });
    setSel(null);
  };

  return (
    <div className="panel">
      <div className="panel-head"><h3>Pre-acreditación · fechas 2026</h3></div>
      <p className="muted small">
        Solo puedes pre-acreditarte en la <b>fecha en curso</b> (la que el staff de GP3 haya iniciado).
        {ultFecha ? <> Usaremos como base los datos de tu última carrera ({ultFecha.n} · {ultFecha.circuito}).</> : <> Usaremos los datos de tu ficha.</>}
      </p>

      {bloqueado && (
        <div className="reject-msg">
          <AlertTriangle size={20} />
          <div>
            <b>Pre-acreditación bloqueada</b>
            <p>Reportaste un error en tu ficha. No puedes pre-acreditarte hasta resolverlo: acércate al <b>staff de GP3 en pista</b> para corregir tus datos y continuar tu acreditación por el conducto normal.</p>
          </div>
        </div>
      )}

      <div className="fecha-list">
        {todas.map((f) => {
          const pre = yaPre(f.id);
          const activa = enCurso(f.id);
          return (
            <div key={f.id} className={`fecha-card ${sel === f.id ? "sel" : ""} ${!activa ? "off" : ""}`}>
              <div className="fecha-main">
                <span className="fecha-serie">{f.serie}{activa && <em className="live">● EN CURSO</em>}</span>
                <b>{f.n}</b>
                <span className="fecha-when"><Calendar size={13} /> {f.txt}</span>
                <span className="fecha-where"><MapPin size={13} /> {f.circuito}</span>
              </div>
              <div className="fecha-cta">
                <button className="btn-link" onClick={() => setAviso({ ...f, modo: "trazado" })}><Map size={14} /> Trazado</button>
                {pre && pre.estado === "acreditado"
                  ? <span className="state-chip ok"><BadgeCheck size={14} /> Acreditado · {pre.folio}</span>
                  : pre
                    ? <span className="state-chip blue"><Check size={14} /> Pre-acreditado</span>
                    : bloqueado
                      ? <button className="btn-disabled" onClick={() => setAviso({ ...f, modo: "bloqueado" })}>No disponible</button>
                      : activa
                        ? (sel === f.id
                          ? <button className="btn-ghost" onClick={() => setSel(null)}>Cerrar</button>
                          : <button className="btn-secondary" onClick={() => setSel(f.id)}>Revisar y confirmar <ChevronRight size={15} /></button>)
                        : <button className="btn-disabled" onClick={() => setAviso({ ...f, modo: "nodisp" })}>No disponible</button>}
              </div>
            </div>
          );
        })}
      </div>

      {fecha && enCurso(fecha.id) && !yaPre(fecha.id) && !bloqueado && (
        <div className="confirm-box">
          <h4>Confirma tu pre-acreditación</h4>
          <div className="confirm-grid">
            <ConfRow k="Fecha" v={`${fecha.n} · ${fecha.txt}`} />
            <ConfRow k="Autódromo" v={fecha.circuito} />
            <ConfRow k="Piloto" v={nombreCompleto(piloto)} />
            <ConfRow k="Dorsal" v={`#${piloto.dorsal}`} mono />
            <ConfRow k="Categoría" v={piloto.categoria} />
            <ConfRow k="Equipo" v={piloto.equipo} />
            <ConfRow k="Moto" v={`${piloto.marcaMoto} ${piloto.modeloMoto}`} />
            <ConfRow k="DNI" v={piloto.dni} mono />
          </div>
          <p className="muted small">¿Algún dato cambió? Repórtalo en <b>Mi ficha</b> y el staff lo corregirá. Al confirmar, el staff podrá emitir tu pase al llegar al autódromo.</p>
          <button className="btn-primary full" onClick={confirmar}><Check size={16} /> Confirmar pre-acreditación</button>
        </div>
      )}

      {aviso && aviso.modo === "bloqueado" && (
        <Modal onClose={() => setAviso(null)} icon={<AlertTriangle size={22} />} titulo="Pre-acreditación bloqueada">
          Reportaste un error en tu ficha. Debes acercarte al <b>staff de GP3 en pista</b> para corregir tus datos antes de poder pre-acreditarte.
        </Modal>
      )}
      {aviso && aviso.modo === "nodisp" && (
        <Modal onClose={() => setAviso(null)} icon={<Clock size={22} />} titulo="Fecha no disponible aún">
          La pre-acreditación de <b>{aviso.n}</b> ({aviso.circuito}) se iniciará por el <b>staff de GP3</b> según el calendario agendado. Cuando la fecha esté en curso, aparecerá habilitada aquí.
        </Modal>
      )}
      {aviso && aviso.modo === "trazado" && (
        <TrazadoModal fecha={aviso} campeonato={piloto.campeonato} onClose={() => setAviso(null)} />
      )}
    </div>
  );
}
const snapshotDe = (p) => ({
  nombre: nombreCompleto(p), dni: p.dni, dorsal: p.dorsal, categoria: p.categoria,
  campeonato: p.campeonato, equipo: p.equipo, moto: `${p.marcaMoto} ${p.modeloMoto}`.trim(), licencia: p.licencia || "",
});

function PilotoHistoria({ db, piloto }) {
  const mis = db.resultados.filter((r) => r.pilotoId === piloto.id);
  const byFecha = {};
  mis.forEach((r) => { (byFecha[r.fechaId] = byFecha[r.fechaId] || []).push(r); });
  const fechas = Object.keys(byFecha).sort((a, b) => (TODAS_FECHAS[b]?.ini || "").localeCompare(TODAS_FECHAS[a]?.ini || ""));
  const totalPts = mis.reduce((s, r) => s + r.puntos, 0);
  return (
    <div className="panel">
      <div className="panel-head"><h3>Mi historia en GP3</h3><span className="big-pts">{fmtPts(totalPts)} <em>pts acumulados</em></span></div>
      {fechas.length === 0 && <div className="empty">Todavía no hay carreras registradas para tu ficha.</div>}
      <div className="timeline">
        {fechas.map((fid) => {
          const f = TODAS_FECHAS[fid];
          const rs = byFecha[fid];
          const carrera = rs.find((r) => r.tanda === "Carrera");
          const pole = rs.find((r) => r.tanda === "Pole");
          const fechaPts = rs.reduce((s, r) => s + r.puntos, 0);
          const cpos = carrera ? carrera.pos : 0;
          return (
            <div key={fid} className="tl-item">
              <span className={`pos-badge ${cpos === 1 ? "p1" : cpos === 2 ? "p2" : cpos === 3 ? "p3" : ""}`}>{cpos > 0 ? `P${cpos}` : "—"}</span>
              <div className="tl-body">
                <b>{f?.n} · {f?.circuito}</b>
                <span className="muted small">{f?.txt} · {(carrera || pole)?.categoria}</span>
                {pole && <span className="tl-pole">Pole {pole.pos > 0 ? `P${pole.pos}` : "—"} · {fmtPts(pole.puntos)} pts</span>}
              </div>
              <span className="tl-pts">{fmtPts(fechaPts)} pts</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function PilotoRanking({ db, piloto }) {
  const data = construirRanking(db, piloto.campeonato, piloto.categoria);
  return <RankingShare data={data} campeonato={piloto.campeonato} categoria={piloto.categoria} resaltar={piloto.id} />;
}

function RankingShare({ data, campeonato, categoria, resaltar }) {
  if (data.filas.length === 0) {
    return (<div className="panel"><div className="panel-head"><h3>Ranking · {categoria}</h3></div><div className="empty">Sin puntajes cargados para esta categoría todavía.</div></div>);
  }
  const MED = { 1: "#F4C84B", 2: "#C9D2DC", 3: "#D8965A" };
  const n = data.fechaIds.length;
  const gt = `46px minmax(0,1fr) repeat(${n}, 40px) 60px`;
  return (
    <div className="rkd">
      <div className="rkd-stripe" />
      <div className="rkd-head">
        <img className="rkd-logo" src={LOGO_GP3} alt="GP3 Sports LATAM" />
        <div className="rkd-title">Ranking 2026<span>{categoria} · {campeonato.split(" - ")[0]}</span></div>
        <CampLogo campeonato={campeonato} size={30} />
      </div>
      <div className="rkg">
        <div className="rkg-row head" style={{ gridTemplateColumns: gt }}>
          <span className="c-rk">#</span>
          <span className="c-nm">Piloto</span>
          {data.fechaIds.map((fid) => <span key={fid} className="c-f">{TODAS_FECHAS[fid]?.n.replace(" Fecha", "ª")}</span>)}
          <span className="c-tot">Total</span>
        </div>
        {data.filas.map((row, i) => (
          <div key={row.pilotoId} className={`rkg-row ${i < 3 ? "pod" : ""} ${row.pilotoId === resaltar ? "me" : ""}`} style={{ gridTemplateColumns: gt }}>
            <span className="c-rk">{i < 3 ? <span className="medal" style={{ background: MED[i + 1] }}>{i + 1}</span> : i + 1}</span>
            <span className="c-nm"><span className="dor">{row.dorsal}</span><span className="pn">{row.nombre}</span></span>
            {data.fechaIds.map((fid) => <span key={fid} className="c-f">{row.celdas[fid] != null ? fmtPts(row.celdas[fid]) : "·"}</span>)}
            <span className="c-tot">{fmtPts(row.total)}</span>
          </div>
        ))}
      </div>
      <div className="rkd-foot">GP3 Sports LATAM · Temporada 2026</div>
    </div>
  );
}

/* ============================================================
   ACREDITACIÓN (staff en pista)
   ============================================================ */
function AcreditacionFlow({ db, persist }) {
  const upcoming = [...SERIES.CAV, ...SERIES.CCV].filter((f) => !f.historica).sort((a, b) => a.ini.localeCompare(b.ini));
  const enCursoIds = upcoming.filter((f) => db.fechasEstado?.[f.id] === "en_curso").map((f) => f.id);
  const def = enCursoIds[0] || upcoming.find((f) => f.ini >= new Date().toISOString().slice(0, 10))?.id || upcoming[0].id;
  const [fechaId, setFechaId] = useState(def);
  const [q, setQ] = useState("");
  const [pase, setPase] = useState(null);
  const [editPiloto, setEditPiloto] = useState(null);
  const [cobrando, setCobrando] = useState(null);

  const fecha = TODAS_FECHAS[fechaId];
  const serie = fechaId.startsWith("cav") ? "CAV" : "CCV";
  const pilotosFecha = db.pilotos.filter((p) => (CAMP_SERIES[p.campeonato] || []).includes(serie));
  const acrDe = (pid) => db.acreditaciones.find((a) => a.pilotoId === pid && a.fechaId === fechaId);
  const prioridad = (p) => {
    const a = acrDe(p.id);
    if (a?.estado === "acreditado") return 4;
    if (p.estadoFicha === "rechazada") return 1;
    if (a?.estado === "pre-acreditado") return 0;
    if (p.estadoFicha === "confirmada") return 2;
    return 3;
  };
  const filtrados = pilotosFecha.filter((p) => {
    const t = q.trim().toLowerCase(); if (!t) return true;
    return nombreCompleto(p).toLowerCase().includes(t) || String(p.dorsal) === t || (p.dni || "").toLowerCase().replace(/[.\s]/g, "").includes(t.replace(/[.\s]/g, ""));
  }).sort((a, b) => prioridad(a) - prioridad(b) || (Number(a.dorsal) || 999) - (Number(b.dorsal) || 999));
  const nPre = pilotosFecha.filter((p) => acrDe(p.id)?.estado === "pre-acreditado").length;

  const toggleFecha = (fid) => {
    const cur = db.fechasEstado?.[fid] === "en_curso";
    persist({ ...db, fechasEstado: { ...db.fechasEstado, [fid]: cur ? "cerrada" : "en_curso" } });
  };
  const emitir = (piloto, cobro) => {
    const ex = acrDe(piloto.id);
    const folio = ex?.folio || folioNuevo(db);
    const reg = { id: ex?.id || `acr-${piloto.id}-${fechaId}`, pilotoId: piloto.id, fechaId, estado: "acreditado", folio, validado: new Date().toISOString(), acreditador: db.acreditador, creado: ex?.creado || new Date().toISOString(), snapshot: ex?.snapshot || snapshotDe(piloto), cobro: cobro || ex?.cobro || null };
    let abonos = db.abonos || [];
    if (cobro?.modo === "abono" && (cobro.abono || 0) > 0 && ex?.estado !== "acreditado") {
      abonos = [...abonos, { id: `ab-${Date.now()}`, pilotoId: piloto.id, fechaId, monto: cobro.abono, moneda: cobro.moneda, medioPago: cobro.medioPago, ts: new Date().toISOString() }];
    }
    const otras = db.acreditaciones.filter((a) => a.id !== reg.id);
    persist({ ...db, acreditaciones: [...otras, reg], abonos });
    setCobrando(null);
    setPase({ reg, piloto, fecha });
  };
  const guardarEdicion = (data) => {
    persist({ ...db, pilotos: db.pilotos.map((p) => (p.id === data.id ? { ...data, estadoFicha: "confirmada" } : p)) });
    setEditPiloto(null);
    setCobrando({ ...data, estadoFicha: "confirmada" }); // Paso 2: cobro / abono
  };

  if (pase) return <PaseView {...pase} onBack={() => setPase(null)} />;
  if (editPiloto) return (
    <div className="panel">
      <div className="panel-head"><h3>Paso 1 · Editar ficha · {nombreCompleto(editPiloto)}</h3><button className="btn-ghost" onClick={() => setEditPiloto(null)}><X size={14} /> Cancelar</button></div>
      <div className="info-bar"><ClipboardCheck size={15} /> Revisa y completa los datos del piloto. Al guardar pasarás al cobro y luego a la emisión del pase.</div>
      {editPiloto.estadoFicha === "rechazada" && <div className="inline-warn"><AlertTriangle size={15} /> El piloto reportó un error en su ficha — corrígelo antes de continuar.</div>}
      <StaffEditForm piloto={editPiloto} onSave={guardarEdicion} onCancel={() => setEditPiloto(null)} />
    </div>
  );

  return (
    <div className="staff">
      <FechaMaintainer db={db} upcoming={upcoming} toggleFecha={toggleFecha} />

      <div className="staff-bar">
        <div className="staff-fecha">
          <span className="muted small">Acreditando en</span>
          <select className="sel-fecha" value={fechaId} onChange={(e) => setFechaId(e.target.value)}>
            {upcoming.map((f) => (
              <option key={f.id} value={f.id}>{(f.id.startsWith("cav") ? "CAV" : "CCV")} · {f.n} · {f.circuito}{db.fechasEstado?.[f.id] === "en_curso" ? " (en curso)" : ""}</option>
            ))}
          </select>
        </div>
        <div className="search"><Search size={16} /><input placeholder="Buscar por dorsal, nombre o documento…" value={q} onChange={(e) => setQ(e.target.value)} /></div>
      </div>

      {db.fechasEstado?.[fechaId] !== "en_curso" && <div className="inline-warn"><Clock size={15} /> Esta fecha no está en curso. Inícialas en el mantenedor para habilitar la pre-acreditación de los pilotos.</div>}

      {nPre > 0 && <div className="info-bar"><ClipboardCheck size={15} /> {nPre} piloto(s) pre-acreditado(s) en esta fecha — emite e imprime su pase para firmar, timbrar y entregar a CAMOD.</div>}

      <div className="staff-list">
        {filtrados.length === 0 && <div className="empty">Sin pilotos para esta búsqueda en {fecha.n}.</div>}
        {filtrados.map((p) => {
          const a = acrDe(p.id);
          const reportado = p.estadoFicha === "rechazada";
          return (
            <div key={p.id} className={`staff-row ${reportado ? "flagged" : ""}`}>
              <span className="row-dorsal">{p.dorsal}</span>
              <CampLogo campeonato={p.campeonato} size={34} />
              <div className="row-info"><b>{nombreCompleto(p)}</b><span className="muted small">{p.categoria} · {p.equipo} · {p.dni}</span></div>
              <div className="row-state">
                {a?.estado === "acreditado" ? <span className="state-chip ok"><BadgeCheck size={14} /> {a.folio}</span>
                  : reportado ? <span className="state-chip red"><AlertTriangle size={14} /> Reportó error</span>
                  : a?.estado === "pre-acreditado" ? <span className="state-chip blue"><Check size={14} /> Pre-acreditado</span>
                  : p.estadoFicha === "confirmada" ? <span className="state-chip ok2"><Check size={14} /> Ficha OK</span>
                  : <span className="state-chip warn"><Clock size={14} /> Sin confirmar</span>}
              </div>
              <div className="row-cta">
                {a?.estado === "acreditado"
                  ? <><button className="btn-ghost" onClick={() => setPase({ reg: a, piloto: p, fecha })}><Printer size={15} /> Ver / imprimir pase</button><button className="btn-outline sm" onClick={() => setEditPiloto(p)}><Pencil size={14} /> Editar</button></>
                  : <button className="btn-secondary sm" onClick={() => setEditPiloto(p)}><Pencil size={14} /> Editar y acreditar</button>}
              </div>
            </div>
          );
        })}
      </div>
      {cobrando && <CobroModal db={db} piloto={cobrando} fecha={fecha} onClose={() => setCobrando(null)} onConfirm={(cobro) => emitir(cobrando, cobro)} />}
    </div>
  );
}

function FechaMaintainer({ db, upcoming, toggleFecha }) {
  const [open, setOpen] = useState(false);
  const activas = upcoming.filter((f) => db.fechasEstado?.[f.id] === "en_curso").length;
  return (
    <div className="maint">
      <button className="maint-head" onClick={() => setOpen(!open)}>
        <Power size={16} /> <b>Mantenedor de fechas</b>
        <span className="maint-count">{activas} en curso</span>
        <ChevronRight size={16} className={`chev ${open ? "rot" : ""}`} />
      </button>
      {open && (
        <div className="maint-body">
          <p className="muted small">Inicia una fecha para habilitar la pre-acreditación de los pilotos de esa serie. Ciérrala al terminar el evento.</p>
          {upcoming.map((f) => {
            const on = db.fechasEstado?.[f.id] === "en_curso";
            return (
              <div key={f.id} className="maint-row">
                <span className="serie-tag">{f.id.startsWith("cav") ? "CAV" : "CCV"}</span>
                <div className="maint-info"><b>{f.n}</b><span className="muted small">{f.txt} · {f.circuito}</span></div>
                <button className={`toggle ${on ? "on" : ""}`} onClick={() => toggleFecha(f.id)}>
                  {on ? <><Power size={13} /> En curso</> : <>Cerrada</>}
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

function StaffEditForm({ piloto, onSave, onCancel }) {
  const [f, setF] = useState(piloto);
  const campo = (k, v) => setF((s) => ({ ...s, [k]: v }));
  return (
    <>
      <FichaFields data={f} edit onChange={campo} />
      <div className="panel-actions">
        <button className="btn-ghost" onClick={onCancel}><X size={14} /> Cancelar</button>
        <button className="btn-primary" onClick={() => onSave(f)}><Save size={15} /> Guardar y continuar al cobro</button>
      </div>
    </>
  );
}

/* -------- Cobro de la fecha / abono anual (al validar para imprimir el pase) -------- */
function CobroModal({ db, piloto, fecha, onClose, onConfirm }) {
  const modo = modoDe(piloto.campeonato);
  const monedas = monedasDe(piloto.campeonato);
  const medios = mediosDe(piloto.campeonato);
  const multi = monedas.length > 1;
  const bloqueada = catBloqueada(piloto.categoria);
  const otras = CATEGORIAS.filter((c) => c !== piloto.categoria && !catBloqueada(c));
  const sug = (cat, mo, factor = 1) => { const v = valorSugerido(cat, mo); return v == null ? "" : String(Math.round(v * factor)); };
  const abonadoPrevio = modo === "abono" ? (db.abonos || []).filter((a) => a.pilotoId === piloto.id).reduce((s, a) => s + (Number(a.monto) || 0), 0) : 0;

  const [moneda, setMoneda] = useState(monedas[0]);
  const [med, setMed] = useState(medios[0]);
  const [m1, setM1] = useState(modo === "fecha" ? sug(piloto.categoria, monedas[0]) : "");
  const [seg, setSeg] = useState(false);
  const [cat2, setCat2] = useState(otras[0] || "");
  const [m2, setM2] = useState("");
  const [abono, setAbono] = useState("");

  const cambiarMoneda = (mo) => { setMoneda(mo); if (modo === "fecha") { setM1(sug(piloto.categoria, mo)); if (seg) setM2(sug(cat2, mo, 0.5)); } };
  const toggleSeg = () => { const n = !seg; setSeg(n); if (n && modo === "fecha") setM2(sug(cat2, moneda, 0.5)); };
  const cambiarCat2 = (c) => { setCat2(c); if (modo === "fecha") setM2(sug(c, moneda, 0.5)); };

  const sumaItems = (Number(m1) || 0) + (seg ? (Number(m2) || 0) : 0);
  const anual = modo === "abono" ? sumaItems : 0;
  const cobroAhora = modo === "abono" ? (Number(abono) || 0) : sumaItems;
  const saldo = anual - abonadoPrevio - (Number(abono) || 0);
  const valido = !bloqueada && cobroAhora > 0 && !!med;

  const confirmar = () => {
    if (!valido) return;
    const items = [{ categoria: piloto.categoria, factor: 1, monto: Number(m1) || 0 }];
    if (seg && cat2) items.push({ categoria: cat2, factor: 0.5, monto: Number(m2) || 0 });
    const cobro = modo === "abono"
      ? { modo, moneda, medioPago: med, items, anual, abono: Number(abono) || 0, abonadoPrevio, saldo, total: Number(abono) || 0 }
      : { modo, moneda, medioPago: med, items, total: sumaItems };
    onConfirm(cobro);
  };

  return (
    <div className="modal-back" onClick={onClose}>
      <div className="modal cobro" onClick={(e) => e.stopPropagation()}>
        <div className="cobro-head">
          <div><b>Paso 2 · {modo === "abono" ? "Abono de temporada" : "Cobro de la fecha"}</b><span className="muted small">{nombreCompleto(piloto)} · {fecha.n}</span></div>
          {multi
            ? <div className="moneda-sel"><span className="multi-badge">multimoneda</span>{monedas.map((mo) => <button key={mo} className={`mon ${moneda === mo ? "on" : ""}`} onClick={() => cambiarMoneda(mo)}>{mo}</button>)}</div>
            : <span className="moneda-fija">{moneda}{modo === "abono" ? " · anual" : ""}</span>}
        </div>

        {bloqueada ? (
          <div className="reject-msg">
            <AlertTriangle size={20} />
            <div><b>Categoría no disponible</b><p>La categoría <b>{piloto.categoria}</b> no está habilitada para cobro ni acreditación. No es posible emitir el pase para esta categoría.</p></div>
          </div>
        ) : (
          <>
            <div className="cobro-line">
              <div className="cl-cat"><span className="cl-tag">{modo === "abono" ? "Valor anual · 1ª categoría" : "1ª categoría"}</span><b>{piloto.categoria}</b></div>
              <div className="cl-input"><span className="cur">{moneda}</span><input type="number" value={m1} placeholder="0" onChange={(e) => setM1(e.target.value)} /></div>
            </div>
            {modo === "fecha" && valorSugerido(piloto.categoria, moneda) == null && <p className="muted small sug-note">Sin tarifa cargada para {moneda} en esta categoría — ingrésala manualmente.</p>}
            {modo === "abono" && <p className="muted small sug-note">Tarifa anual {moneda} aún no cargada — ingrésala manualmente.</p>}

            {!seg
              ? <button className="add-cat" onClick={toggleSeg}><Plus size={14} /> Agregar segunda categoría (−50%)</button>
              : (
                <div className="cobro-line seg">
                  <div className="cl-cat"><span className="cl-tag">2ª categoría · −50%</span>
                    <select value={cat2} onChange={(e) => cambiarCat2(e.target.value)}>{otras.map((c) => <option key={c} value={c}>{c}</option>)}</select>
                  </div>
                  <div className="cl-input"><span className="cur">{moneda}</span><input type="number" value={m2} placeholder="0" onChange={(e) => setM2(e.target.value)} /><button className="cl-x" onClick={toggleSeg} title="Quitar"><X size={14} /></button></div>
                </div>
              )}

            {modo === "abono" && (
              <div className="abono-box">
                <div className="abono-row"><span>Valor anual {seg ? "(incluye 2ª cat.)" : ""}</span><b>{anual > 0 ? fmtMoneda(anual, moneda) : "—"}</b></div>
                <div className="abono-row"><span>Abonado previo</span><b>{fmtMoneda(abonadoPrevio, moneda)}</b></div>
                <div className="cobro-line abono-input">
                  <div className="cl-cat"><span className="cl-tag">Abono a registrar ahora</span></div>
                  <div className="cl-input"><span className="cur">{moneda}</span><input type="number" value={abono} placeholder="0" onChange={(e) => setAbono(e.target.value)} /></div>
                </div>
                <div className="abono-row saldo"><span>Saldo tras este abono</span><b>{anual > 0 ? fmtMoneda(saldo, moneda) : "—"}</b></div>
              </div>
            )}

            <div className="medios">
              <span className="medios-label">Medio de pago</span>
              <div className="medios-btns">{medios.map((mm) => <button key={mm} className={`medio ${med === mm ? "on" : ""}`} onClick={() => setMed(mm)}>{mm}</button>)}</div>
              {!piloto.campeonato.includes("CCV") && <span className="muted small">Tarjeta no disponible para {piloto.campeonato.split(" - ")[0]}.</span>}
            </div>

            <div className="cobro-total"><span>{modo === "abono" ? "Abono a cobrar ahora" : "Total a cobrar"}</span><b>{fmtMoneda(cobroAhora, moneda)}</b></div>
          </>
        )}

        <div className="panel-actions">
          <button className="btn-ghost" onClick={onClose}><X size={14} /> Cancelar</button>
          <button className="btn-primary" onClick={confirmar} disabled={!valido}><Printer size={15} /> {modo === "abono" ? "Registrar abono y emitir" : "Cobrar y emitir pase"}</button>
        </div>
      </div>
    </div>
  );
}

/* -------- PASE imprimible -------- */
function PaseView({ reg, piloto, fecha, onBack }) {
  const s = reg.snapshot;
  const m = metaDe(s.campeonato);
  const print = () => { document.body.classList.add("printing"); window.print(); setTimeout(() => document.body.classList.remove("printing"), 400); };
  const validadoTxt = reg.validado ? new Date(reg.validado).toLocaleString("es-CL", { dateStyle: "medium", timeStyle: "short" }) : "—";
  return (
    <div className="pase-screen">
      <div className="pase-toolbar no-print">
        <button className="btn-ghost" onClick={onBack}><ArrowLeft size={15} /> Volver</button>
        <button className="btn-primary" onClick={print}><Printer size={16} /> Imprimir pase</button>
      </div>
      <div className="pase-print-root">
        <div className="pase">
          <div className="pase-stripe" />
          <div className="pase-top">
            <div className="pase-brandwrap">
              <img className="pase-logo screen-only" src={LOGO_GP3} alt="GP3 Sports LATAM" />
              <img className="pase-logo print-only" src={LOGO_GP3_BLACK} alt="GP3 Sports LATAM" />
              <CampLogo campeonato={s.campeonato} size={22} />
            </div>
            <div className="pase-folio">{reg.folio}</div>
          </div>
          <div className="pase-body">
            <div className="pase-photo">{fotoDe(piloto) ? <img src={fotoDe(piloto)} alt="" /> : <User size={42} />}</div>
            <div className="pase-dorsal" style={{ background: m.color }}>
              <span className="dl">DORSAL</span><b>{s.dorsal}</b>
              <span className="dl">{m.abbr}</span>
            </div>
            <div className="pase-main">
              <span className="pase-kicker">PASE DE ACREDITACIÓN · TEMPORADA 2026</span>
              <h2>{s.nombre}</h2>
              <div className="pase-rows">
                <PaseField k="DNI / Documento" v={s.dni} />
                <PaseField k="Categoría" v={s.categoria} />
                <PaseField k="Campeonato" v={s.campeonato} />
                <PaseField k="Equipo" v={s.equipo} />
                <PaseField k="Moto" v={s.moto} />
                <PaseField k="Federación" v={federacionDe(s.campeonato)} />
              </div>
            </div>
          </div>
          <div className="pase-event">
            <div><span className="el">FECHA</span><b>{fecha.n}</b><span className="ev">{fecha.txt}</span></div>
            <div><span className="el">AUTÓDROMO</span><b>{fecha.circuito}</b></div>
          </div>
          {reg.cobro && reg.cobro.modo === "abono" ? (
            <div className="pase-cobro">
              <div className="pase-cobro-main">
                <span className="el">ABONO TEMPORADA</span>
                <b>{fmtMoneda(reg.cobro.abono, reg.cobro.moneda)}</b>
                <span className="ev">{reg.cobro.medioPago}</span>
              </div>
              <div className="pase-cobro-items">
                {reg.cobro.anual > 0 && <span>Anual: {fmtMoneda(reg.cobro.anual, reg.cobro.moneda)}</span>}
                {reg.cobro.anual > 0 && <span>Saldo: {fmtMoneda(reg.cobro.saldo, reg.cobro.moneda)}</span>}
              </div>
            </div>
          ) : reg.cobro ? (
            <div className="pase-cobro">
              <div className="pase-cobro-main">
                <span className="el">VALOR FECHA</span>
                <b>{fmtMoneda(reg.cobro.total, reg.cobro.moneda)}</b>
                <span className="ev">{reg.cobro.medioPago}</span>
              </div>
              <div className="pase-cobro-items">
                {reg.cobro.items.map((it, i) => (
                  <span key={i}>{it.categoria}{it.factor < 1 ? " · −50%" : ""}: {fmtMoneda(it.monto, reg.cobro.moneda)}</span>
                ))}
              </div>
            </div>
          ) : null}
          <div className="pase-foot">
            <div className="pase-firma"><div className="firma-line" /><span>Firma y timbre · Acreditación GP3</span></div>
            <div className="pase-valida"><span className="el">VALIDADO POR</span><b>{reg.acreditador}</b><span className="ev">{validadoTxt}</span></div>
          </div>
          <div className="pase-edge" />
        </div>
        <p className="pase-note no-print">Preforma base. Cuando me pases el formato oficial CAMOD/FMC y los logos, dejo el pase calcado al diseño definitivo con timbres reales.</p>
      </div>
    </div>
  );
}
const PaseField = ({ k, v }) => (<div className="pf"><span>{k}</span><b>{v}</b></div>);

