function OrgPilotos({ db, persist }) {
  const [editId, setEditId] = useState(null);
  const [q, setQ] = useState("");
  const [campAbierto, setCampAbierto] = useState(null);
  const [verPerfil, setVerPerfil] = useState(null);
  const vacio = { id: "", dorsal: "", categoria: CATEGORIAS[0], campeonato: CAMPEONATOS[1], nombres: "", apellidos: "", dni: "", fechaNacimiento: "", pais: "Chile", provincia: "", localidad: "", domicilio: "", telefono: "", nombreAcompanante: "", telefonoAcompanante: "", mail: "", marcaMoto: "", modeloMoto: "", equipo: "", licencia: "", estadoFicha: "pendiente", foto: "" };
  const [f, setF] = useState(vacio);
  const campo = (k, v) => setF((s) => ({ ...s, [k]: v }));
  const editar = (p) => { setEditId(p.id); setF(p); };
  const nuevo = () => { setEditId("__new__"); setF(vacio); };
  const guardar = () => {
    if (!f.nombres || !f.dni) return;
    const pilotos = editId === "__new__" ? [...db.pilotos, { ...f, id: `p${Date.now()}` }] : db.pilotos.map((p) => (p.id === editId ? f : p));
    persist({ ...db, pilotos }); setEditId(null);
  };

  const exportarExcel = () => {
    const colDef = [
      ["dorsal", "Dorsal"], ["nombres", "Nombres"], ["apellidos", "Apellidos"],
      ["__nombre", "Nombre completo"], ["dni", "DNI / Documento"],
      ["fechaNacimiento", "Fecha de nacimiento"], ["__edad", "Edad"],
      ["categoria", "Categoría"], ["campeonato", "Campeonato"], ["pais", "País"],
      ["provincia", "Provincia"], ["localidad", "Localidad"], ["domicilio", "Domicilio"],
      ["telefono", "Teléfono"], ["nombreAcompanante", "Nombre acompañante"],
      ["telefonoAcompanante", "Teléfono acompañante"], ["mail", "Mail"],
      ["marcaMoto", "Marca de la moto"], ["modeloMoto", "Modelo de la moto"],
      ["equipo", "Equipo"], ["licencia", "Licencia"], ["estadoFicha", "Estado ficha"],
      ["__foto", "Tiene foto"],
    ];
    const filaDe = (p) => {
      const o = {};
      colDef.forEach(([k, label]) => {
        if (k === "__nombre") o[label] = nombreCompleto(p);
        else if (k === "__edad") { const e = edadDe(p.fechaNacimiento); o[label] = e == null ? "" : e; }
        else if (k === "__foto") o[label] = p.foto ? "Sí" : "No";
        else o[label] = p[k] ?? "";
      });
      return o;
    };
    const ordenar = (arr) => [...arr].sort((a, b) =>
      (CATEGORIAS.indexOf(a.categoria) - CATEGORIAS.indexOf(b.categoria)) ||
      ((Number(a.dorsal) || 999) - (Number(b.dorsal) || 999)));
    const anchos = colDef.map(([, label]) => ({ wch: Math.max(label.length, 12) }));
    const todos = db.pilotos;
    const hoy = new Date().toISOString().slice(0, 10);

    const wb = XLSX.utils.book_new();

    // Hoja Resumen
    const r = [];
    r.push(["GP3 Sports · Informe ejecutivo de pilotos"]);
    r.push(["Generado", hoy]);
    r.push(["Total de pilotos", todos.length]);
    r.push([]);
    r.push(["Campeonato", "Total", "Ficha OK", "Pendiente", "Reportó error"]);
    CAMPEONATOS.forEach((camp) => {
      const ps = todos.filter((p) => p.campeonato === camp);
      if (!ps.length) return;
      r.push([camp, ps.length,
        ps.filter((p) => p.estadoFicha === "confirmada").length,
        ps.filter((p) => !p.estadoFicha || p.estadoFicha === "pendiente").length,
        ps.filter((p) => p.estadoFicha === "rechazada").length]);
    });
    r.push([]);
    r.push(["Campeonato", "Categoría", "Pilotos"]);
    CAMPEONATOS.forEach((camp) => {
      const ps = todos.filter((p) => p.campeonato === camp);
      CATEGORIAS.forEach((cat) => {
        const n = ps.filter((p) => p.categoria === cat).length;
        if (n) r.push([camp, cat, n]);
      });
    });
    const wsR = XLSX.utils.aoa_to_sheet(r);
    wsR["!cols"] = [{ wch: 42 }, { wch: 16 }, { wch: 12 }, { wch: 12 }, { wch: 14 }];
    XLSX.utils.book_append_sheet(wb, wsR, "Resumen");

    // Hoja Todos
    const wsAll = XLSX.utils.json_to_sheet(ordenar(todos).map(filaDe));
    wsAll["!cols"] = anchos;
    XLSX.utils.book_append_sheet(wb, wsAll, "Todos");

    // Una hoja por campeonato
    CAMPEONATOS.forEach((camp) => {
      const ps = ordenar(todos.filter((p) => p.campeonato === camp));
      if (!ps.length) return;
      const ws = XLSX.utils.json_to_sheet(ps.map(filaDe));
      ws["!cols"] = anchos;
      const nombreHoja = (CAMP_META[camp]?.abbr || camp).slice(0, 28);
      XLSX.utils.book_append_sheet(wb, ws, nombreHoja);
    });

    XLSX.writeFile(wb, `GP3-Informe-Pilotos-${hoy}.xlsx`);
  };
  const t = q.trim().toLowerCase();
  const lista = db.pilotos.filter((p) => !t || nombreCompleto(p).toLowerCase().includes(t) || String(p.dorsal) === t || (p.dni || "").toLowerCase().replace(/[.\s]/g, "").includes(t.replace(/[.\s]/g, "")));
  const orden = (p) => [CAMPEONATOS.indexOf(p.campeonato), CATEGORIAS.indexOf(p.categoria), Number(p.dorsal) || 999];
  const listaOrd = [...lista].sort((a, b) => {
    const oa = orden(a), ob = orden(b);
    for (let i = 0; i < 3; i++) if (oa[i] !== ob[i]) return oa[i] - ob[i];
    return 0;
  });

  if (verPerfil) return <PerfilPiloto db={db} piloto={verPerfil} onClose={() => setVerPerfil(null)} />;

  return (
    <div className="panel">
      <div className="panel-head"><h3>Ficha base de pilotos</h3><div className="head-actions"><button className="btn-outline sm" onClick={exportarExcel} disabled={!db.pilotos.length}><Download size={15} /> Informe ejecutivo</button><button className="btn-primary sm" onClick={nuevo}><Plus size={15} /> Nuevo piloto</button></div></div>
      <p className="muted small">Lo que cargues aquí es lo que el piloto verá precargado para validar o reportar.</p>
      <div className="search org"><Search size={16} /><input placeholder="Buscar piloto por nombre, dorsal o documento…" value={q} onChange={(e) => setQ(e.target.value)} /></div>

      <div className="org-pilotos">
        {t ? (
          /* Modo búsqueda: filas que coinciden, agrupadas por campeonato y categoría */
          <>
            {(() => {
              let lastCamp = null, lastCat = null;
              const out = [];
              listaOrd.forEach((p) => {
                if (p.campeonato !== lastCamp) {
                  lastCamp = p.campeonato; lastCat = null;
                  out.push(<div key={`c-${p.campeonato}`} className="grp-camp"><CampLogo campeonato={p.campeonato} size={26} /> {p.campeonato}</div>);
                }
                if (p.categoria !== lastCat) {
                  lastCat = p.categoria;
                  out.push(<div key={`cat-${p.campeonato}-${p.categoria}`} className="grp-cat">{p.categoria}</div>);
                }
                out.push(<OrgPilotoRow key={p.id} p={p} onEdit={() => editar(p)} onVer={() => setVerPerfil(p)} />);
              });
              return out;
            })()}
            {listaOrd.length === 0 && <div className="empty">Sin coincidencias para “{q}”.</div>}
          </>
        ) : (
          /* Modo por defecto: agrupado por campeonato; las fichas se abren por grupo */
          <div className="camp-groups">
            {CAMPEONATOS.map((camp) => {
              const ps = listaOrd.filter((p) => p.campeonato === camp);
              if (ps.length === 0) return null;
              const abierto = campAbierto === camp;
              return (
                <div key={camp} className={`camp-card ${abierto ? "open" : ""}`}>
                  <button className="camp-card-head" onClick={() => setCampAbierto(abierto ? null : camp)}>
                    <CampLogo campeonato={camp} size={28} />
                    <span className="camp-card-name">{camp}</span>
                    <span className="camp-card-count">{ps.length} piloto{ps.length === 1 ? "" : "s"}</span>
                    <ChevronRight size={18} className={`camp-card-chev ${abierto ? "open" : ""}`} />
                  </button>
                  {abierto && (
                    <div className="camp-card-body">
                      {(() => {
                        let lastCat = null; const out = [];
                        ps.forEach((p) => {
                          if (p.categoria !== lastCat) { lastCat = p.categoria; out.push(<div key={`cat-${camp}-${p.categoria}`} className="grp-cat">{p.categoria}</div>); }
                          out.push(<OrgPilotoRow key={p.id} p={p} onEdit={() => editar(p)} onVer={() => setVerPerfil(p)} />);
                        });
                        return out;
                      })()}
                    </div>
                  )}
                </div>
              );
            })}
            {db.pilotos.length === 0 && <div className="empty">Aún no hay pilotos cargados. Crea el primero con “Nuevo piloto”.</div>}
            <div className="hint-row"><Search size={14} /> Abre un campeonato, busca un piloto o crea uno nuevo para ver y editar las fichas.</div>
          </div>
        )}
      </div>

      {editId && (
        <div className="confirm-box">
          <h4>{editId === "__new__" ? "Nuevo piloto" : "Editar piloto"}</h4>
          <FichaFields data={f} edit onChange={campo} />
          <div className="panel-actions">
            <button className="btn-ghost" onClick={() => setEditId(null)}><X size={14} /> Cancelar</button>
            <button className="btn-primary" onClick={guardar}><Save size={15} /> Guardar ficha</button>
          </div>
        </div>
      )}
    </div>
  );
}

function OrgPuntajes({ db, persist, onLock }) {
  const [camp, setCamp] = useState("CCV - Campeonato Chile de Velocidad");
  const [cat, setCat] = useState("Gp3 Cup Promocional");
  const [editing, setEditing] = useState(null); // {resultado, tanda, pos, puntos, motivo}
  const [showLog, setShowLog] = useState(false);

  const pilotoNombre = (id) => { const p = db.pilotos.find((x) => x.id === id); return p ? `#${p.dorsal} ${nombreCompleto(p)}` : "—"; };
  const resultadosCat = db.resultados
    .filter((r) => r.campeonato === camp && r.categoria === cat)
    .sort((a, b) => (TODAS_FECHAS[a.fechaId]?.ini || "").localeCompare(TODAS_FECHAS[b.fechaId]?.ini || "") || pilotoNombre(a.pilotoId).localeCompare(pilotoNombre(b.pilotoId)));
  const log = (db.cambiosLog || []).filter((l) => l.campeonato === camp && l.categoria === cat);
  const data = construirRanking(db, camp, cat);

  const abrir = (r) => setEditing({ resultado: r, tanda: r.tanda, pos: String(r.pos), puntos: String(r.puntos), motivo: "" });
  const setCampo = (k, v) => setEditing((s) => {
    const next = { ...s, [k]: v };
    if (k === "pos" || k === "tanda") { const pos = Number(k === "pos" ? v : next.pos); if (pos) next.puntos = String(calcularPuntos(camp, next.tanda, pos)); }
    return next;
  });
  const guardar = () => {
    const e = editing; if (!e || !e.motivo.trim()) return;
    const r = e.resultado;
    const nPos = Number(e.pos), nPun = Number(e.puntos);
    const sinCambio = nPos === r.pos && nPun === r.puntos && e.tanda === r.tanda;
    if (sinCambio) { setEditing(null); return; }
    const f = TODAS_FECHAS[r.fechaId];
    const entrada = {
      id: `log-${Date.now()}`, ts: new Date().toISOString(), usuario: "admin",
      campeonato: camp, categoria: cat, piloto: pilotoNombre(r.pilotoId), fecha: `${f?.serie || ""} ${f?.n || r.fechaId}`.trim(),
      antes: { tanda: r.tanda, pos: r.pos, puntos: r.puntos },
      despues: { tanda: e.tanda, pos: nPos, puntos: nPun },
      motivo: e.motivo.trim(),
    };
    const resultados = db.resultados.map((x) => (x.id === r.id ? { ...x, tanda: e.tanda, pos: nPos, puntos: nPun } : x));
    persist({ ...db, resultados, cambiosLog: [entrada, ...(db.cambiosLog || [])] });
    setEditing(null);
  };

  return (
    <div className="panel">
      <div className="panel-head"><h3>Puntajes y ranking</h3><span className="admin-chip"><Unlock size={12} /> admin · escala {escalaDe(camp)} <button className="btn-link" onClick={onLock}>bloquear</button></span></div>

      <div className="bulk-box">
        <div><b>Carga masiva desde Excel</b><p className="muted small">La carga de puntajes se hace por importación de la planilla <code>Base_Puntajes</code> (mismo formato del Excel que analizamos). Aquí solo se editan registros existentes, con bitácora.</p></div>
        <button className="btn-outline" disabled><Plus size={14} /> Importar Excel (pronto)</button>
      </div>

      <div className="filtros">
        <SelectInline label="Campeonato" v={camp} opts={CAMPEONATOS} onChange={(v) => { setCamp(v); setEditing(null); }} />
        <SelectInline label="Categoría" v={cat} opts={CATEGORIAS} onChange={(v) => { setCat(v); setEditing(null); }} />
      </div>

      <div className="res-head"><span className="carga-title">Resultados cargados</span><span className="muted small">Solo edición · cada cambio queda registrado con motivo</span></div>
      <div className="res-list">
        {resultadosCat.length === 0 && <div className="empty">No hay resultados cargados para esta categoría. Impórtalos desde el Excel.</div>}
        {resultadosCat.map((r) => {
          const f = TODAS_FECHAS[r.fechaId];
          return (
            <div key={r.id} className="res-row">
              <span className="res-fecha">{f?.serie} · {f?.n.replace(" Fecha", "ª")}</span>
              <div className="res-info"><b>{pilotoNombre(r.pilotoId)}</b><span className="muted small">{r.tanda} · P{r.pos}</span></div>
              <span className="res-pts">{fmtPts(r.puntos)} pts</span>
              <button className="btn-outline sm" onClick={() => abrir(r)}><Pencil size={13} /> Editar</button>
            </div>
          );
        })}
      </div>

      {editing && (
        <div className="confirm-box">
          <h4>Editar resultado</h4>
          <div className="edit-meta">{pilotoNombre(editing.resultado.pilotoId)} · {TODAS_FECHAS[editing.resultado.fechaId]?.serie} {TODAS_FECHAS[editing.resultado.fechaId]?.n}</div>
          <div className="carga-grid">
            <label>Tanda<select value={editing.tanda} onChange={(e) => setCampo("tanda", e.target.value)}><option>Carrera</option><option>Pole</option></select></label>
            <label>Posición<input type="number" min="1" max="20" value={editing.pos} onChange={(e) => setCampo("pos", e.target.value)} /></label>
            <label>Puntos<input type="number" step="0.5" value={editing.puntos} onChange={(e) => setCampo("puntos", e.target.value)} /></label>
            <div className="carga-pts">escala: {fmtPts(calcularPuntos(camp, editing.tanda, Number(editing.pos) || 0))} pts</div>
          </div>
          <label className="motivo-label">Motivo del cambio <em>· obligatorio</em>
            <textarea className="motivo-area" rows={2} placeholder="Ej: corrección por reclamo aceptado en comisaría deportiva / doble carrera sumada / error de digitación…" value={editing.motivo} onChange={(e) => setEditing((s) => ({ ...s, motivo: e.target.value }))} />
          </label>
          <div className="panel-actions">
            <button className="btn-ghost" onClick={() => setEditing(null)}><X size={14} /> Cancelar</button>
            <button className="btn-primary" onClick={guardar} disabled={!editing.motivo.trim()}><Save size={15} /> Guardar cambio</button>
          </div>
        </div>
      )}

      <RankingTable data={data} />

      <button className="log-toggle" onClick={() => setShowLog(!showLog)}>
        <Clock size={15} /> <b>Historial de versiones</b>
        <span className="maint-count">{log.length}</span>
        <ChevronRight size={16} className={`chev ${showLog ? "rot" : ""}`} />
      </button>
      {showLog && (
        <div className="log-list">
          {log.length === 0 && <div className="empty">Sin cambios registrados en esta categoría.</div>}
          {log.map((l) => (
            <div key={l.id} className="log-item">
              <div className="log-top">
                <b>{l.piloto}</b><span className="muted small">{l.fecha}</span>
                <span className="log-ts">{new Date(l.ts).toLocaleString("es-CL", { dateStyle: "short", timeStyle: "short" })} · {l.usuario}</span>
              </div>
              <div className="log-diff">
                <span className="log-before">{l.antes.tanda} · P{l.antes.pos} · {fmtPts(l.antes.puntos)} pts</span>
                <ChevronRight size={13} />
                <span className="log-after">{l.despues.tanda} · P{l.despues.pos} · {fmtPts(l.despues.puntos)} pts</span>
              </div>
              <div className="log-motivo">“{l.motivo}”</div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function OrgCalendario() {
  const [trazado, setTrazado] = useState(null);
  return (
    <div className="panel">
      <div className="panel-head"><h3>Calendario 2026</h3></div>
      {["CCV", "CAV"].map((serie) => (
        <div key={serie} className="cal-block">
          <h4 className="cal-h">{serie === "CCV" ? "CCV · Campeonato Chile de Velocidad" : "CAV · Campeonato Argentino de Velocidad"}</h4>
          <div className="cal-list">
            {SERIES[serie].map((f) => (
              <div key={f.id} className={`cal-row ${f.historica ? "hist" : ""}`}>
                <b>{f.n}</b>
                <span><Calendar size={13} /> {f.txt}</span>
                <span><MapPin size={13} /> {f.circuito}</span>
                <button className="btn-link cal-traz" onClick={() => setTrazado({ ...f, serie, campeonato: serie === "CCV" ? "CCV - Campeonato Chile de Velocidad" : "CAV - Campeonato Argentino de Velocidad" })}><Map size={14} /> Trazado</button>
                {f.historica && <span className="tag-hist">histórica</span>}
              </div>
            ))}
          </div>
        </div>
      ))}
      {trazado && <TrazadoModal fecha={trazado} campeonato={trazado.campeonato} onClose={() => setTrazado(null)} />}
    </div>
  );
}

/* ============================================================
   TRAZADO (ficha de circuito imprimible / descargable)
   ============================================================ */
function buildTrazadoSVG(fecha, campeonato) {
  const c = CIRCUITOS[fecha.circuito] || CIRCUITOS["Autódromo Buenos Aires"];
  const m = metaDe(campeonato);
  const d = SHAPES[c.shape] || SHAPES.default;
  const esc = (s) => String(s || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  const rows = [
    ["Longitud", c.longitud], ["Curvas", c.curvas], ["Sentido", c.sentido],
    ["Homologación", c.homolog], ["Ubicación", c.loc], ["País", c.pais],
  ];
  const rowsSvg = rows.map((r, i) => `
    <text x="40" y="${586 + i * 30}" font-family="Inter,Arial" font-size="13" fill="#6A7282">${esc(r[0])}</text>
    <text x="200" y="${586 + i * 30}" font-family="Inter,Arial" font-size="13" font-weight="600" fill="#16171D">${esc(r[1])}</text>
    <line x1="40" y1="${596 + i * 30}" x2="520" y2="${596 + i * 30}" stroke="#E6E9EF"/>`).join("");
  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 560 800" width="560" height="800">
  <rect width="560" height="800" fill="#FFFFFF"/>
  <rect width="560" height="96" fill="#16171D"/>
  <rect width="560" height="8" fill="${m.color}"/>
  <text x="40" y="50" font-family="Saira Condensed,Arial" font-size="26" font-weight="800" fill="#FFFFFF">GP3 SPORTS · TRAZADO</text>
  <text x="40" y="76" font-family="Inter,Arial" font-size="14" fill="#AEB3BF">${esc(campeonato)}</text>
  <rect x="430" y="28" width="92" height="42" rx="8" fill="${m.color}"/>
  <text x="476" y="55" text-anchor="middle" font-family="Saira Condensed,Arial" font-size="20" font-weight="800" fill="#FFFFFF">${esc(m.abbr)}</text>
  <text x="40" y="150" font-family="Saira Condensed,Arial" font-size="30" font-weight="800" fill="#16171D">${esc(fecha.circuito)}</text>
  <text x="40" y="180" font-family="Inter,Arial" font-size="15" fill="#E11D2A" font-weight="700">${esc(fecha.n)} · ${esc(fecha.txt)}</text>
  <g transform="translate(60,230) scale(1.05)">
    <path d="${d}" fill="none" stroke="#16171D" stroke-width="16" stroke-linejoin="round" stroke-linecap="round"/>
    <path d="${d}" fill="none" stroke="#E11D2A" stroke-width="4" stroke-dasharray="2 10" stroke-linecap="round"/>
  </g>
  <rect x="40" y="540" width="480" height="2" fill="#16171D"/>
  <text x="40" y="566" font-family="Saira Condensed,Arial" font-size="16" font-weight="700" fill="#16171D">FICHA TÉCNICA</text>
  ${rowsSvg}
  <text x="40" y="780" font-family="Inter,Arial" font-size="11" fill="#9AA1AE">Esquema referencial — el trazado oficial se incorporará al cargar los mapas definitivos.</text>
</svg>`;
}

function TrazadoModal({ fecha, campeonato, onClose }) {
  const svg = buildTrazadoSVG(fecha, campeonato);
  const print = () => { document.body.classList.add("printing-traz"); window.print(); setTimeout(() => document.body.classList.remove("printing-traz"), 400); };
  const descargar = () => {
    try {
      const blob = new Blob([svg], { type: "image/svg+xml" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url; a.download = `trazado-${fecha.circuito.replace(/\s+/g, "_")}-${fecha.n.replace(/\s+/g, "")}.svg`;
      document.body.appendChild(a); a.click(); document.body.removeChild(a);
      setTimeout(() => URL.revokeObjectURL(url), 1000);
    } catch (e) { alert("Si la descarga no inicia, usa Imprimir → Guardar como PDF."); }
  };
  return (
    <div className="modal-back" onClick={onClose}>
      <div className="modal traz-modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-bar no-print">
          <b><Map size={16} /> Trazado del circuito</b>
          <div className="modal-actions">
            <button className="btn-outline sm" onClick={descargar}><Download size={14} /> SVG</button>
            <button className="btn-primary sm" onClick={print}><Printer size={14} /> Imprimir</button>
            <button className="btn-ghost sm" onClick={onClose}><X size={15} /></button>
          </div>
        </div>
        <div className="traz-print-root" dangerouslySetInnerHTML={{ __html: svg }} />
      </div>
    </div>
  );
}

/* ---------- Modal genérico ---------- */
function Modal({ onClose, icon, titulo, children }) {
  return (
    <div className="modal-back" onClick={onClose}>
      <div className="modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-icon">{icon}</div>
        <h4>{titulo}</h4>
        <p>{children}</p>
        <button className="btn-primary full" onClick={onClose}>Entendido</button>
      </div>
    </div>
  );
}

/* ============================================================
   Ranking
   ============================================================ */
function construirRanking(db, campeonato, categoria) {
  const rs = db.resultados.filter((r) => r.campeonato === campeonato && r.categoria === categoria);
  const fechaIds = [...new Set(rs.map((r) => r.fechaId))].sort((a, b) => (TODAS_FECHAS[a]?.ini || "").localeCompare(TODAS_FECHAS[b]?.ini || ""));
  const porPiloto = {};
  rs.forEach((r) => {
    if (!porPiloto[r.pilotoId]) porPiloto[r.pilotoId] = { pilotoId: r.pilotoId, celdas: {}, total: 0 };
    porPiloto[r.pilotoId].celdas[r.fechaId] = (porPiloto[r.pilotoId].celdas[r.fechaId] || 0) + r.puntos;
    porPiloto[r.pilotoId].total += r.puntos;
  });
  const filas = Object.values(porPiloto).map((row) => {
    const p = db.pilotos.find((x) => x.id === row.pilotoId);
    return { ...row, nombre: p ? nombreCompleto(p) : "—", dorsal: p?.dorsal ?? "" };
  }).sort((a, b) => b.total - a.total);
  return { fechaIds, filas };
}
function RankingTable({ data, resaltar }) {
  if (data.filas.length === 0) return <div className="empty">Sin puntajes cargados para esta categoría.</div>;
  return (
    <div className="rk-wrap">
      <table className="rk">
        <thead><tr>
          <th className="rk-pos">#</th><th className="rk-name">Piloto</th>
          {data.fechaIds.map((fid) => <th key={fid} className="rk-f">{TODAS_FECHAS[fid]?.n.replace(" Fecha", "ª")}</th>)}
          <th className="rk-tot">Total</th>
        </tr></thead>
        <tbody>
          {data.filas.map((row, i) => (
            <tr key={row.pilotoId} className={resaltar === row.pilotoId ? "me" : ""}>
              <td className="rk-pos">{i + 1}</td>
              <td className="rk-name"><div className="nmrow"><span className="rk-dorsal">{row.dorsal}</span>{row.nombre}</div></td>
              {data.fechaIds.map((fid) => <td key={fid} className="rk-f">{row.celdas[fid] != null ? fmtPts(row.celdas[fid]) : "·"}</td>)}
              <td className="rk-tot">{fmtPts(row.total)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

