function FichaFields({ data, edit, onChange }) {
  const ar = esArg(data);
  const visibles = FICHA_FIELDS.filter((f) => !f.arOnly || ar);
  return (
    <div className="fields">
      {visibles.map((f) => {
        const val = data[f.k];
        const age = f.k === "fechaNacimiento" ? edadDe(val) : null;
        return (
          <div key={f.k} className={`field ${f.wide ? "wide" : ""}`}>
            <label>{f.label}{f.arOnly && <em className="req-ar"> · solo AR</em>}</label>
            {edit ? (
              <div className="field-row">
                {f.type === "select"
                  ? <select className="inp" value={val ?? ""} onChange={(e) => onChange(f.k, e.target.value)}>{f.opts.map((o) => <option key={o} value={o}>{o}</option>)}</select>
                  : <input className="inp" type={f.type === "date" ? "date" : "text"} value={val ?? ""} onChange={(e) => onChange(f.k, e.target.value)} />}
                {age != null && <span className="age-badge">{age} años</span>}
              </div>
            ) : (
              <div className="field-row">
                <div className={`field-v ${f.mono ? "mono" : ""}`}>{val || "—"}</div>
                {age != null && <span className="age-badge">{age} años</span>}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}
const ConfRow = ({ k, v, mono }) => (<div className="cr"><span>{k}</span><b className={mono ? "mono" : ""}>{v}</b></div>);
const SelectInline = ({ label, v, opts, onChange }) => (
  <label className="sel-inline">{label}<select value={v} onChange={(e) => onChange(e.target.value)}>{opts.map((o) => <option key={o} value={o}>{o}</option>)}</select></label>
);

